                $smartlock_value = intval($smartlock_value);
            }
            if($variable_type == VARIABLETYPE_FLOAT)
            {
                $smartlock_value = floatval($smartlock_value);
            }
            if($variable_type == VARIABLETYPE_STRING)
            {
                $smartlock_value = strval($smartlock_value);
            }
        }
        else
        {
            $smartlock_value = 0;
        }
